  timestamp≜1772150400
  reply_to≜"none"
  protocol≜1
}

⟦Σ:Types⟧{
  Index≜{0,1,2}
  Player≜{X,O}
  Cell≜{Empty,X,O}
  Board≜(Index×Index)→Cell
  Pos≜{r:Index,c:Index}
  Game≜{board:Board,next:Player}
  Bool≜{true,false}
}

⟦Γ:Rules⟧{
  ∀b:Board,r∈Index,c∈Index:b(r,c)∈Cell
  ∀g:Game,m:Pos:validMove(g,m)⇒(g.board(m.r,m.c)=Empty ∧ ¬gameOver(g.board))
  ∀g:Game,m:Pos:(g.board(m.r,m.c)=Empty ∧ ¬gameOver(g.board))⇒validMove(g,m)
  ∀b:Board,p:Player:win(b,p)⇒((∃i∈Index:b(i,0)=p∧b(i,1)=p∧b(i,2)=p) ∨ (∃j∈Index:b(0,j)=p∧b(1,j)=p∧b(2,j)=p) ∨ (b(0,0)=p∧b(1,1)=p∧b(2,2)=p) ∨ (b(0,2)=p∧b(1,1)=p∧b(2,0)=p))
  ∀b:Board:(win(b,X)∨win(b,O)∨full(b))⇒gameOver(b)
  ∀b:Board:gameOver(b)⇒(win(b,X)∨win(b,O)∨full(b))
}

⟦Λ:Funcs⟧{
  full≜λ(b).∀r∈Index,c∈Index:b(r,c)≠Empty
  win≜λ(b,p).(∃i∈Index:b(i,0)=p∧b(i,1)=p∧b(i,2)=p) ∨ (∃j∈Index:b(0,j)=p∧b(1,j)=p∧b(2,j)=p) ∨ (b(0,0)=p∧b(1,1)=p∧b(2,2)=p) ∨ (b(0,2)=p∧b(1,1)=p∧b(2,0)=p)
  validMove≜λ(g,m).g.board(m.r,m.c)=Empty ∧ ¬gameOver(g.board)
  gameOver≜λ(b).win(b,X)∨win(b,O)∨full(b)
  isGameOver≜λ(g).gameOver(g.board)
}

