}

⟦Σ:Types⟧{
  Priority≜{1,2,3,4,5}
  Time≜Int
  TaskId≜String
  WorkerId≜String
  Task≜{id:TaskId, priority:Priority, deadline:Time, assigned_to:WorkerId∪None}
  Worker≜{id:WorkerId, current_task:TaskId∪None, active:Bool}
  TaskList≜Seq<Task>
}

⟦Γ:Rules⟧{
  ∀t∈Task:priority(t)∈Priority ∧ deadline(t)∈Time
  ∀w∈Worker:(current_task(w)=None)∨∃!t∈Task:(id(t)=current_task(w) ∧ assigned_to(t)=id(w))
  ∀t∈Task:(assigned_to(t)=None)∨∃!w∈Worker:id(w)=assigned_to(t)
  ∀w∈Worker,t∈Task:
    assign(w,t)=true⇒active(w)=true ∧ current_task(w)=None ∧ assigned_to(t)=None ∧
    ¬∃u∈Task:(assigned_to(u)=None ∧ (priority(u)>priority(t) ∨ (priority(u)=priority(t) ∧ deadline(u)<deadline(t))))
}

⟦Λ:Funcs⟧{
  nextUnassignedHighest≜λ(tasks).
    if |{t∈tasks | assigned_to(t)=None}|=0 then None
    else head(sort({t∈tasks | assigned_to(t)=None},
      λ(a,b).(priority(a)>priority(b))∨(priority(a)=priority(b)∧deadline(a)<deadline(b))))
}

⟦Ε⟧⟨δ≜0.92;φ≜100;τ≜◊⁺⁺⟩
